#!/usr/bin/perl
use strict;
use warnings;

sub load_config_patterns {
    my $config_file = shift || 'validation_config.txt';
    my %patterns;
    
    if (-f $config_file) {
        open my $fh, '<', $config_file or die "Cannot open config: $!";
        while (my $line = <$fh>) {
            chomp $line;
            next if $line =~ /^\s*#/ || $line =~ /^\s*$/;
            if ($line =~ /^(\w+)\s*=\s*(.+)$/) {
                $patterns{$1} = $2;
            }
        }
        close $fh;
    }
    
    return \%patterns;
}

sub validate_with_pattern {
    my ($test_string, $pattern) = @_;
    
    my $compiled_pattern = eval "qr/$pattern/";
    if ($@) {
        die "Error compiling pattern: $@";
    }
    
    return $test_string =~ /$compiled_pattern/;
}

sub validate_with_eval {
    my ($test_string, $user_pattern) = @_;
    
    my $result = eval "\$test_string =~ /$user_pattern/";
    if ($@) {
        die "Error evaluating pattern: $@";
    }
    
    return $result;
}

