sub command_line_mode {
    my ($pattern, @test_strings) = @_;
    
    if (!$pattern || @test_strings == 0) {
        print "Usage: $0 <pattern> <test_string1> [test_string2 ...]\n";
        print "   or: $0 --interactive\n";
        exit 1;
    }
    
    for my $test_string (@test_strings) {
        my $result = eval "\$test_string =~ /$pattern/";
